import React, { useState, useEffect } from "react";
import { ReactComponent as BoliviaSVG } from "../assets/bolivia.svg";

const MapaBolivia = ({ onDepartamentoClick, empresas }) => {
    const [departamentoSeleccionado, setDepartamentoSeleccionado] = useState(null);

    const manejarClick = (e) => {
        const nombre = e.target.getAttribute("name");
        if (nombre) {
            setDepartamentoSeleccionado(nombre);
            if (onDepartamentoClick) {
                onDepartamentoClick(nombre);
            }
        }
    };

    useEffect(() => {
        const paths = document.querySelectorAll(".bolivia-map path");
        paths.forEach((path) => {
            const nombreDep = path.getAttribute("name");
            if (nombreDep === departamentoSeleccionado) {
                path.style.fill = "#000000ff"; // Seleccionado
            } else {
                path.style.fill = "#32302fff"; // Por defecto
            }
        });
    }, [departamentoSeleccionado]);

    return (
        // Contenedor principal: Centra el contenido
        <div className="w-full flex items-center justify-center">
            {/*
                Contenedor del Mapa:
                - max-w-lg: Limita el ancho máximo para evitar desbordamiento en pantallas muy grandes.
                - aspect-square: Fuerza una proporción de 1:1 (cambia a otra si el mapa es más ancho/alto).
                - w-full: Ocupa todo el ancho disponible dentro del límite.
            */}
            <div className="w-full max-w-lg aspect-square p-4">
                <BoliviaSVG
                    // El SVG ocupa todo el espacio de su contenedor con la proporción fijada.
                    className="bolivia-map w-full h-full cursor-pointer object-contain"
                    onClick={manejarClick}
                />
            </div>
        </div>
    );
};

export default MapaBolivia;
